return [{
  json: {
    jobTitle:        $input.first().json.body.job_title        || "",
    jobLocation:     $input.first().json.body.location_focus   || "",
    experience:      $input.first().json.body.experience_level || "",
    techStack:       Array.isArray($input.first().json.body.tech_stack)        ? $input.first().json.body.tech_stack        : [],
    industry:        $input.first().json.body.industry_preference              || "",
    excludeIndustry: Array.isArray($input.first().json.body.exclude_industry)  ? $input.first().json.body.exclude_industry  : [],
    employmentType:  $input.first().json.body.employment_type  || "",
    jobBoards:       Array.isArray($input.first().json.body.job_boards)        ? $input.first().json.body.job_boards        : []
  }
}];

const input = $input.first().json;

const formatValue = (value) => {
  if (Array.isArray(value)) return value.length ? value.join(", ") : "";
  return value ?? "";
};

const skipKeys = new Set(["jobBoards", "Userprompt"]);
const criteria = Object.entries(input)
  .filter(([key, value]) => {
    if (skipKeys.has(key)) return false;
    if (value === undefined || value === null || value === "") return false;
    if (Array.isArray(value) && value.length === 0) return false;
    return true;
  })
  .map(([key, value]) => {
    const cleanKey = key.replace(/([A-Z])/g, " $1").replace(/^./, s => s.toUpperCase()).trim();
    return `- ${cleanKey}: ${formatValue(value)}`;
  })
  .join("\n");

const boardPatterns = {
  linkedin:         "site:linkedin.com/jobs",
  indeed:           "site:indeed.com",
  greenhouse:       "site:boards.greenhouse.io",
  lever:            "site:jobs.lever.co",
  wellfound:        "site:wellfound.com/jobs",
  remotive:         "site:remotive.com/remote-jobs",
  workable:         "site:apply.workable.com",
  ashby:            "site:jobs.ashbyhq.com",
  simplyhired:      "site:simplyhired.com",
  ziprecruiter:     "site:ziprecruiter.com/jobs",
  remoterocketship: "site:remoterocketship.com",
  weworkremotely:   "site:weworkremotely.com",
  ycombinator:      "site:workatastartup.com"
};

const jobBoards = Array.isArray(input.jobBoards) ? input.jobBoards : [];
if (jobBoards.length === 0) {
  console.warn("Warning: jobBoards array is empty.");
  return [{ json: { ...input, Userprompt: "No job boards to search. Please check input data." } }];
}

const boardInstructions = jobBoards.map((board, i) => {
  const key = board.toLowerCase().trim();
  const siteFilter = boardPatterns[key] || `site:${key}`;
  return `Board ${i + 1} - ${board}:\n  Search query: "${input.jobTitle}" ${siteFilter}\n  Scrape each result URL and return up to 5 listings. Record all available fields including salary, full job description, and the direct application link.`;
}).join("\n\n");

const Userprompt = `Search each job board below separately using Firecrawl.\n\nFor each board:\n1. Run the search query provided\n2. Scrape each result URL to get FULL listing details including job description, salary, requirements, and the direct application link\n3. Return up to 5 listings per board\n\nJob criteria to match against:\n${criteria || "(No criteria specified - return best available matches)"}\n\nJob boards to search:\n${boardInstructions}`;

return [{ json: { ...input, Userprompt } }];

const raw = items[0].json.output;

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/s);
  if (match) {
    try { parsed = JSON.parse(match[1].trim()); }
    catch (e) { throw new Error('Parse Companies: Invalid JSON - ' + err.message); }
  } else {
    throw new Error('Parse Companies: Invalid JSON - ' + err.message);
  }
}

const companies = parsed.companies || [];
if (!parsed.companies || parsed.companies.length === 0) {
  parsed.companies = [];
}

return companies.map(c => ({
  json: {
    companyName:     c.companyName     || '',
    roleTitle:       c.roleTitle       || '',
    jobLocation:     c.jobLocation     || '',
    employmentType:  c.employmentType  || '',
    techStack:       c.techStack       || [],
    salary:          c.salary          || '',
    jobDescription:  c.jobDescription  || '',
    applicationLink: c.applicationLink || c.link || '',
    postedDate:      c.postedDate      || '',
    source:          c.source          || ''
  }
}));
